"""
MKT Original Layer — Jeremiah chapters 33–36
Run: python3 scripts/zc-original-jeremiah-33-36-fill.py

Key lexical decisions:
- 33:3 'call to me' (qra elai): the only place in Jeremiah where YHWH directly
  invites prayer; the hidden things (nistarot) echo Deut 29:29 — things YHWH
  chooses to reveal beyond the covenant minimum.
- 33:8 double-forgiveness: 'cleanse them ... forgive all the iniquity AND rebellion'
  — two distinct terms for different dimensions of sin.
- 33:15-16: the Branch oracle repeated with a shift: in 23:6 the king is named
  'YHWH Tsidqenu'; here the CITY (Jerusalem) receives that name — the community
  takes on the character of its king.
- 33:20-21: creation-covenant as guarantee — the permanence of day and night
  underwrites the permanence of the Davidic and Levitical covenants.
- 34:14: the shemittah/debt-release law (Deut 15:12-18 / Exod 21:2) — the slave-
  release covenant violation is a breach of the foundational Sabbatical structure.
- 34:18: the covenant-cutting ceremony (berit bein habtarim) — the Gen 15 prototype
  where the calf halves are passed between, making the covenant-maker the implied
  sacrifice if they violate it.
- 35:14: Jonadab's command vs. YHWH's Torah — the Rechabite object lesson.
- 36:23: Jehoiakim burns the scroll — the anti-type to Josiah's hearing/tearing
  the law (2 Kgs 22:11-13); the word cannot be destroyed (v.28, v.32).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

JER_ORIGINAL = {
  "33": {
    "1": "<p>The oracle is explicitly dated to Jeremiah&apos;s imprisonment (<em>asur bachatzer hamatara</em>, confined in the court of the guard — cf. 32:2-3). The temporal marker &apos;a second time&apos; (<em>shenit</em>) links this oracle to the previous (ch. 32&apos;s land-purchase) as a second confirming word of restoration. Hope spoken from prison is more credible than hope spoken from freedom; the circumstances contradict the message, which forces the question of its source.</p>",
    "2": "<p><strong>koh-amar YHWH osah zaot YHWH yotzer otah lehachinah YHWH shemo</strong> (<em>kōh-ʾāmar Yhwh ʿōśeh zōʾt Yhwh yōṣēr ʾōtāh lĕhăḵînāh Yhwh šĕmô</em>): &apos;Thus says the LORD who made the earth, the LORD who formed it and established it — the LORD is his name.&apos; Three creation verbs — <em>asah</em> (made), <em>yatzar</em> (formed, the potter&apos;s verb of Gen 2:7 and Isa 45:18), <em>hachin</em> (established/fixed) — ground the restoration promise in creative authority. The same God who formed the earth can reform the nation. <em>YHWH shemo</em> (the LORD is his name) is the doxological formula asserting exclusive divine identity (cf. Amos 5:8; 9:6; Isa 42:8).</p>",
    "3": "<p><strong>qra elai ve&apos;e&apos;enecha ve&apos;agidah lecha gedolot vebetzurot lo yada&apos;ta</strong> (<em>qrāʾ-ʾēlay wĕʾeʿĕnekā wĕʾaggîdāh lĕkā gĕdōlôt ûbĕṣūrôt lōʾ yādāʿtā</em>): &apos;Call to me and I will answer you, and will tell you great and hidden things that you have not known.&apos; This is the only verse in Jeremiah where YHWH directly invites prayer. <em>Gedolot</em> (great things) and <em>betzurot</em> (hidden/fortified/inaccessible things) are revelation beyond ordinary knowledge. <em>Batzur</em> shares a root with the word for fortress/cliff (<em>batzor</em>): these are things &apos;fortified away&apos; from human access, revealed only by divine disclosure (cf. Deut 29:29: &apos;the hidden things belong to the LORD our God, but the revealed things belong to us and to our children forever&apos;). Jesus&apos;s invitation &apos;Ask and it will be given you, seek and you will find, knock and the door will be opened&apos; (Matt 7:7) extends this promise to everyone in the new covenant.</p>",
    "4": "<p>The houses torn down (<em>hetusim</em>) and the siege ramps (<em;>solelot</em>) built against them — the very material of the city&apos;s destruction is being used as raw material for the city&apos;s defense. The oracle speaks of judgment (v. 5) and restoration (v. 6) in tight sequence — the same God who hides his face (v. 5) will reveal health and healing (v. 6).</p>",
    "5": "<p><strong>ba&apos;im lhilachem et-haKasdim umale otam et-pigrye ha-adam asher hiketi be-api uvachamati</strong>: &apos;The Chaldeans are coming to fight and to fill those houses with the corpses of men whom I struck down in my anger and wrath.&apos; YHWH&apos;s &apos;hiding his face&apos; (<em>histarti panai</em>) from the city is the covenant-withdrawal formula: the withdrawal of divine presence, more catastrophic than any military defeat. The phrase appears in the &apos;hidden face&apos; texts of Deut 31:17-18 and Isa 54:8 — a covenantal concept rather than a mere absence.</p>",
    "6": "<p><strong>hineni ma&apos;aleh la arukha umarpeh verapatim vegalitilahem atzumat shalom ve&apos;emet</strong> (<em>hinnĕnî maʿăleh lāh ʾărûkāh ûmarpēʾ ûrĕpāʾtîm wĕgillêtî lāhem ʿaṣûmat šālôm wĕʾĕmet</em>): &apos;Behold, I will bring health and healing to it; I will heal them and reveal to them an abundance of prosperity and security.&apos; Three restoration terms: <em>arukah</em> (new skin/healing, specifically wound-closure — cf. 8:22 where there is no healing), <em>marpeh</em> (cure/medicine), and <em>shalom ve-emet</em> (peace and faithfulness). The medical vocabulary reverses the wound imagery of the book: the incurable wound (30:12-13) will be healed. The divine healer of 30:17 (&apos;I will restore your health and heal your wounds&apos;) is here specified with the language of abundant prosperity.</p>",
    "7": "<p><strong>veshavti et-shevut Yehudah ve&apos;et shevut Yisrael uvenetim otam ke-varishonah</strong>: &apos;I will restore the fortunes of Judah and Israel and rebuild them as they were at the beginning.&apos; <em>Shavti shevut</em> (restore the fortunes) — the idiom, literally &apos;I will turn the turning,&apos; appears at the center of restoration promises throughout Jeremiah (29:14; 30:3, 18; 31:23; 32:44; 33:11, 26). The Hebrew construction uses the infinitive absolute of <em>shuv</em> (return) to express the completeness of the reversal. Both Judah and Israel — the divided kingdoms — will be restored together, a promise that encompasses all twelve tribes.</p>",
    "8": "<p><strong>vetihartim mikol avonam asher chate&apos;u li vesalachti lekol avonoteihem asher chate&apos;u li</strong>: &apos;I will cleanse them from all the iniquity by which they sinned against me, and I will forgive all the iniquity and rebellion by which they sinned against me.&apos; The double-forgiveness formula: <em>tihar</em> (cleanse/purify — the priestly term for ritual purification, Lev 13-14) and <em>salach</em> (forgive/pardon — the judicial/covenantal term; only YHWH is ever the subject of <em>salach</em> in the OT). Two different dimensions of sin: <em>avon</em> (iniquity, the guilt and liability of sin) and <em>pisha</em> (rebellion, the active willful defiance). Cleansing addresses the defilement; forgiveness addresses the guilt. Both are promised. This anticipates the new covenant&apos;s permanent forgiveness of 31:34 (&apos;I will remember their sin no more&apos;) and the NT&apos;s &apos;forgiveness of sins and cleansing from all unrighteousness&apos; (1 John 1:9).</p>",
    "9": "<p><strong>vehayetah li leshem lesason ulitehillah uletiferet</strong>: &apos;This city will be to me a name of joy, a praise, and a glory before all the nations.&apos; The three terms — <em>shem</em> (name/reputation), <em>sason</em> (joy), <em>tehillah</em> (praise), <em>tiferet</em> (glory/beauty) — are the covenant blessings inverted from the curses. Deut 28:37 pronounced Jerusalem would become a <em>mashal</em> (proverb) and <em>shenina</em> (byword) of shame. Here it becomes a name of joy and praise — the exact opposite. The nations shuddering (<em>pachadu</em>) at YHWH&apos;s goodness inverts their watching Jerusalem&apos;s destruction with schadenfreude (cf. Lam 1:7; 2:15-16).</p>",
    "10": "<p>The double designation of desolation — &apos;without man or beast&apos; (<em>ein adam ve-ein behema</em>) — repeats the judgment formula of 32:43 and anticipates its reversal. The &apos;cities of Judah and streets of Jerusalem&apos; are the spaces where the covenant community&apos;s life was lived — commercial, domestic, and liturgical. The oracle promises that those same spaces will be refilled with joy.</p>",
    "11": "<p><strong>qol sasson veqol simchah qol chatan veqol kallah</strong> (<em>qôl śāśôn wĕqôl śimḥāh qôl ḥātān wĕqôl kallāh</em>): &apos;The voice of joy and the voice of gladness, the voice of the bridegroom and the voice of the bride.&apos; This four-fold &apos;voice of&apos; formula appears in both judgment (7:34; 16:9; 25:10: &apos;I will silence the voice of joy ... the voice of the bridegroom and bride&apos;) and restoration (33:11). The liturgical fragment embedded in the verse — <em>hodu et-YHWH Tzvaot ki tov YHWH ki le-olam chasdo</em> (Give thanks to the LORD of hosts, for the LORD is good, for his steadfast love endures forever) — is the refrain of Ps 136 and 1 Chronicles 16:34. The Psalmic doxology of the temple liturgy will be heard again: the silenced song of 7:34 is restored.</p>",
    "12": "<p>The desolate land reoccupied by shepherds and flocks represents the return of ordinary pastoral life — a sign of covenant normalcy. The shepherd-and-flock image has been used throughout Jeremiah for covenantal relationships (ch. 23; cf. Ezek 34). Its return signals that the covenant community is functioning again under proper care.</p>",
    "13": "<p><strong>ba-arei hahar ba-arei hashfela uve-arei hanegev uve-eretz Binyamin uvsvivot Yerushalaim</strong>: The geographic catalog — hill country, Shephelah, Negev, Benjamin, Jerusalem environs — represents all of Judah&apos;s territory, from north to south, from the highlands to the lowlands. The sheep passing under the shepherd&apos;s hands to be counted (<em>ya&apos;avru al-yadei moneh</em>) echoes Ezek 20:37 (&apos;I will make you pass under the rod&apos; — a shepherd&apos;s counting method) and implies a covenantal census: every sheep accounted for, none lost. This imagery directly informs Jesus&apos;s parable of the shepherd who counts and seeks the one lost sheep (Luke 15:4-7).</p>",
    "14": "<p><strong>hineh yamim baim neum YHWH vahaqimoti et-hadavar hatov asher dibarti el-beit Yisrael ve&apos;al-beit Yehudah</strong>: &apos;The days are coming, declares the LORD, when I will fulfill the good promise I made to the house of Israel and the house of Judah.&apos; <em>Hadavar hatov</em> (the good word/promise) — the specific content follows in vv. 15-18. This is a meta-promise: YHWH promises to keep his previous promises, establishing a second level of covenantal assurance. The phrase <em>yamim baim</em> (days are coming) is Jeremiah&apos;s standard eschatological marker, pointing beyond the immediate historical horizon.</p>",
    "15": "<p><strong>bayamim hahem uveet hahi atzmich leDavid tzemach tzaddiq</strong> (<em>bYyāmîm hāhēm ûbāʿēt hahîʾ ʾaṣmîaḥ lĕdāwid ṣemaḥ ṣaddîq</em>): &apos;In those days and at that time I will cause a righteous Branch to spring up for David.&apos; The Branch-oracle of 23:5 is repeated almost verbatim — the second occurrence establishes this as Jeremiah&apos;s central messianic promise, worthy of repetition. <em>Tzemach</em> (branch/shoot) appears as a messianic title again at Zech 3:8 (&apos;my servant the Branch&apos;) and 6:12 (&apos;the man whose name is the Branch, and he will branch out from his place and build the temple of the LORD&apos;). The branching-out image carries growth and organic life: the dead stump of the Davidic line will sprout again, as in Isa 11:1 (&apos;a shoot from the stump of Jesse&apos;).</p>",
    "16": "<p><strong>beyamim hahem tivasha Yehudah viYerushalaim tishkon lavetch veze asher yiqra lah YHWH Tzidqenu</strong> (<em>bYyāmîm hāhēm tiwwāšēaʿ yĕhûdāh wîrûšālaim tiškon lābeṭaḥ wĕzeh ʾăšer yiqrāʾ-lāh Yhwh ṣidqênû</em>): &apos;In those days Judah will be saved and Jerusalem will dwell in safety. And this is the name by which it will be called: &apos;The LORD is our righteousness.&apos;&apos; Note the crucial shift from 23:6: there, the King is named <em>YHWH Tsidqenu</em>; here, the city Jerusalem receives that name. The community takes on the king&apos;s name and character — the theological principle that the people are defined by who rules them. When the Righteous Branch reigns, his righteousness becomes the city&apos;s defining characteristic. Rev 21:2-3 captures this: the new Jerusalem coming down from God, &apos;the dwelling of God is with man&apos; — the city and its king are inseparable.</p>",
    "17": "<p><strong>ki koh-amar YHWH lo yikaret leDavid ish yoshev al-kise beit Yisrael</strong> (<em>kî kōh-ʾāmar Yhwh lōʾ-yikkārēt lĕdāwid ʾîš yōšēb ʿal-kissēʾ bêt yiśrāʾēl</em>): &apos;For thus says the LORD: There will never fail to be a man from David&apos;s line to sit on the throne of the house of Israel.&apos; <em>Lo yikaret leDavid ish</em> (there will not be cut off from David a man) echoes the unconditional form of the Davidic covenant in 2 Sam 7:16 (&apos;your house and your kingdom will endure forever before me&apos;). After the Jehoiachin curse of 22:30 (&apos;record this man as childless&apos;), this reaffirmation of the Davidic line is remarkable: the curse on the throne-succession through natural descendants does not annul the covenant promise fulfilled in a different way.</p>",
    "18": "<p><strong>velakkohanim halevi&apos;im lo-yikaret ish milfanai ma&apos;aleh olah umaqtir minchah</strong>: &apos;And the Levitical priests shall never lack a man in my presence to offer burnt offerings, to burn grain offerings, and to make sacrifices continually.&apos; The pairing of Davidic kingship (v. 17) and Levitical priesthood (v. 18) in the eternal covenant points toward the NT&apos;s union of the two offices in Christ. Hebrews&apos; central argument is precisely the fulfillment: Jesus is both the Davidic king (Heb 1:3-5) and the Melchizedekian high priest (Heb 4:14-5:10; 7:1-28) who supersedes the Levitical priesthood. The inseparability of the two offices promised here is achieved in Christ&apos;s single person.</p>",
    "19": "<p>The messenger formula introducing the covenant-guarantee oracle. The shift from restoration promises (vv. 1-18) to the cosmic-covenant argument (vv. 20-26) is indicated by a fresh divine word — YHWH is not merely promising but arguing from creation order for the reliability of what has been promised.</p>",
    "20": "<p><strong>koh amar YHWH im-tafiru et-beriti hayom ve-et beriti halaylah</strong> (<em>kōh ʾāmar Yhwh ʾim-tāpērû ʾet-bĕrîtî hayyôm wĕʾet-bĕrîtî hallaylāh</em>): &apos;Thus says the LORD: If you can break my covenant with the day and my covenant with the night, so that day and night no longer come at their appointed time.&apos; YHWH uses creation order as collateral for covenant promise: the regularity of day and night (<em>moadam</em>, their appointed times) is YHWH&apos;s covenant with creation (cf. Gen 8:22: &apos;as long as the earth endures, seedtime and harvest, cold and heat, summer and winter, day and night will never cease&apos;). The argument is a fortiori: only if creation&apos;s most fundamental rhythm can be disrupted will the Davidic promise fail. Paul uses similar cosmological argument for the security of divine election in Rom 8:38-39 (nothing in all creation can separate from God&apos;s love in Christ Jesus).</p>",
    "21": "<p><strong>gam-beriti tufer et-David avdi</strong>: &apos;Then my covenant with my servant David could also be broken.&apos; The logical chain: cosmic covenant (day/night) → Davidic covenant → Levitical covenant. All three are bound in a single covenantal fabric. The phrase <em>avdi David</em> (my servant David) is the royal honorific — the same title given to Moses (Deut 34:5), Joshua (Josh 24:29), Isaiah (Isa 20:3), and supremely to the messianic servant of Isa 52:13. It is never given to a reigning king in Jeremiah — it is the title of the idealized king of promise.</p>",
    "22": "<p><strong>kasher lo-yisafer tzeva hashamayim velo yimad chol hayam ken arbeh et-zera David avdi ve&apos;et-haLevi&apos;im meshartai oti</strong>: &apos;As the host of heaven cannot be numbered and the sand of the sea cannot be measured, so I will multiply the offspring of David my servant and the Levites who minister to me.&apos; The innumerable-offspring promise echoes the Abrahamic covenant (Gen 15:5: stars; 22:17: stars and sand; 32:12: sand). Its application to David&apos;s line and the Levites connects the messianic promise to the founding covenantal promise: the Davidic fulfillment is the Abrahamic fulfillment.</p>",
    "23": "<p>The messenger formula signals a new divine communication — a response to a specific objection being raised in the community (v. 24). The oracle addresses those who are drawing theological conclusions from the exile that undermine the covenant promises.</p>",
    "24": "<p><strong>halo ra&apos;ita mah ha-am hazeh dibberu lemor shnei hamishpachot asher bachar YHWH bahem vayim&apos;asem</strong>: &apos;Have you not noticed what these people are saying? &apos;The LORD has rejected the two families he chose.&apos;&apos; The &apos;two families&apos; are the Davidic dynasty and the Levitical priesthood — the two institutions just promised in vv. 17-18. The exile has generated a theology of divine rejection: if YHWH has abandoned Jerusalem, perhaps the covenants are void. The prophetic response does not deny the judgment but disputes the conclusion: discipline ≠ rejection.</p>",
    "25": "<p><strong>koh amar YHWH im-lo beriti yomam valaylah chuqot shamayim va-aretz lo samti</strong>: &apos;Thus says the LORD: If I have not established my covenant with day and night and the fixed orders of heaven and earth.&apos; <em>Chuqot shamayim va-aretz</em> (the fixed orders of heaven and earth) — the same language as &apos;the fixed laws of heaven and earth&apos; in v. 25, referring to the natural laws of creation. These are the visible, daily, undeniable evidence of covenant-keeping: every sunrise is YHWH keeping his covenant with day; every night that ends is YHWH keeping his covenant with night. Creation-faithfulness is the argument for covenant-faithfulness.</p>",
    "26": "<p><strong>ki-eshuv et-shevutam verichhamtim</strong>: &apos;I will restore their fortunes and have mercy on them.&apos; The chapter closes with the restoration formula, now grounded in the cosmic-covenant argument. The descendants of Jacob and David cannot be ultimately rejected because the rejection of the covenants would require the dismantling of creation itself — and the daily evidence of day and night argues against that. <em>Racham</em> (mercy/compassion — from <em>rechem</em>, womb) is the covenant-loyalty term that expresses YHWH&apos;s most intimate commitment to his people: parental, physiological, irreversible.</p>"
  },
  "34": {
    "1": "<p>The oracle is temporally precise: Nebuchadnezzar and his entire coalition (<em>kol-mamlachot eretz memshelet yado</em>, all the kingdoms and peoples under his dominion) — a comprehensive reference to the multi-national Babylonian army described in 2 Kgs 24:2-3 and historically confirmed by the Babylonian Chronicles. The siege of Jerusalem is the backdrop against which Zedekiah receives both a word of judgment and a qualified mercy.</p>",
    "2": "<p><strong>hineni noten et-ha&apos;ir hazot beyad melech Bavel visrafah ba-esh</strong>: &apos;I am going to hand this city over to the king of Babylon, and he will burn it with fire.&apos; The hand-over formula (<em>noten beyad</em>) is the standard divine speech act for delivering a city to an enemy — the same formula used for Israel&apos;s victories in the wilderness (Josh 6:2: &apos;I have given Jericho into your hand&apos;). Here it is inverted: YHWH delivers his own city. The burning of the city (<em>sarafah ba-esh</em>) is the covenant curse of Deut 13:16 applied to an apostate city — Jerusalem is treated as an <em>ir hanidachat</em>, a city devoted to destruction.</p>",
    "3": "<p><strong>velo timalet miyado ki tafas titapes uveyadoh titten</strong>: &apos;You will not escape his grasp but will certainly be captured and handed over to him.&apos; The double infinitive absolute (<em>tafas titapes</em>, captured you will be captured) intensifies the certainty. The personal encounter — &apos;your eyes will look into the eyes of the king of Babylon, and he will speak with you in person&apos; (<em>peh el peh yedaber imach</em>) — is the intimate horror of defeat: face-to-face with your conqueror. The prophecy was fulfilled precisely: Zedekiah was captured, brought before Nebuchadnezzar, and had his sons killed before his eyes before being blinded (39:5-7; 52:9-11; 2 Kgs 25:6-7).</p>",
    "4": "<p><strong>ach shema dvar YHWH Tzidqiyahu melech Yehudah</strong>: &apos;Yet hear the word of the LORD, O Zedekiah king of Judah.&apos; The adversative <em>ach</em> (yet/however) pivots from judgment to the qualified mercy: even for a king whose dynasty is ending, YHWH has a specific word. The content following is not rescue but a mercy within the judgment — a mitigated death rather than a brutal execution.</p>",
    "5": "<p><strong>beshalom tamut uvemisrefot avoteicha hamelachim harishonim</strong>: &apos;You will die in peace. And as spices were burned in honor of your ancestors, the kings who preceded you, so they will burn spices for you and mourn for you, crying, &apos;Alas, lord!&apos;&apos; <em>Beshalom tamut</em> (you will die in peace) means death by natural causes rather than by sword — a qualified mercy within judgment. The burning of spices for a king&apos;s funeral was a royal honor (2 Chron 16:14 for Asa; 21:19 for Jehoram&apos;s failure to receive this honor). Zedekiah receives the minimum of royal dignity in death. The oracle was literally fulfilled: Zedekiah was blinded and imprisoned in Babylon until his death (39:7; 52:11), dying there rather than by execution.</p>",
    "6": "<p>The note of Jeremiah&apos;s public proclamation of this oracle to Zedekiah — while Babylonian armies besieged Jerusalem — underscores the prophetic courage required. The oracle contains both bad news (capture, exile) and qualified good news (survival), making it a message no political or military authority would want proclaimed publicly.</p>",
    "7": "<p><strong>beihilachem chel melech Bavel al-Yerushalaim veal-kol-arei Yehudah hanissarot al-Lachish ve&apos;al-Azekah</strong>: The historical precision: only Lachish and Azekah remained as unconquered fortified cities at this point in the siege. The Lachish Letters (clay ostraca found at Lachish, dated to this period) contain a poignant note from a military commander: &apos;We are watching for the signals of Lachish according to all the indications my lord has given, because we cannot see the signals of Azekah.&apos; Azekah had already fallen when that letter was written — providing remarkable extra-biblical confirmation of Jeremiah&apos;s historical accuracy.</p>",
    "8": "<p><strong>hadavar asher hayah el-Yirmiyahu me&apos;et YHWH achar karat hamelech Tzidqiyahu berit et-kol-ha&apos;am asher biYerushalaim liqro lahem deror</strong>: &apos;The word that came to Jeremiah from the LORD after King Zedekiah had made a covenant with all the people in Jerusalem to proclaim liberty.&apos; <em>Deror</em> (liberty/release) is the technical term of the Jubilee year (Lev 25:10: &apos;proclaim liberty throughout the land&apos;). The covenant to release Hebrew slaves invokes this Jubilee framework — a remarkable moment of covenant renewal under siege pressure that was immediately reversed.</p>",
    "9": "<p><strong>leshallach ish et-avdo ha-ivri ve&apos;et-amatoh ha-ivriyah chofshi</strong>: &apos;Everyone was to release his Hebrew male slave and his Hebrew female slave.&apos; The law behind this action: Exod 21:2 (Hebrew slaves serve six years then go free) and Deut 15:12-18 (the seventh-year shemittah release). The law had apparently been ignored for an extended period — the act of liberation under siege pressure suggests accumulated unpaid obligations, perhaps spanning many sabbatical years. The specificity of &apos;Hebrew&apos; (fellow-covenant-member) slavery makes the violation doubly problematic: enslaving one&apos;s own covenant kin.</p>",
    "10": "<p>The brief moment of obedience: the officials and people entered the covenant (<em>kol-hasarim vekhal-ha-am asher ba&apos;u vaberit</em>) and released their slaves. The sequence — covenant-making, liberation, release — is the pattern of covenant renewal (cf. Neh 10 where similar obligations are undertaken). The response was real and public.</p>",
    "11": "<p><strong>vayashuvu acharei-chen vayashivu et-ha&apos;avadim ve&apos;et-ha&apos;amahos asher shilechu chofshim vayichabshum la&apos;avadim vela&apos;amahos</strong>: &apos;But afterward they turned back and took back the male and female slaves they had freed, forcing them back into slavery.&apos; The reversal is almost immediately: the Babylonian army temporarily lifted the siege (probably to deal with an Egyptian relief force, cf. 37:5-11), and the slave-owners interpreted the lifting of pressure as permission to rescind their covenant vows. The economic calculation overrode the covenant obligation. The irony is profound: they freed the slaves when the enemy was at the gates; they re-enslaved them when the enemy temporarily withdrew.</p>",
    "12": "<p>The messenger formula signals YHWH&apos;s direct response to the breach — the divine word comes specifically because of what happened in vv. 10-11. The response takes the form of ironically mirroring the slave-release with a &apos;release&apos; of judgment against the slave-owners (v. 17).</p>",
    "13": "<p><strong>koh amar YHWH elohe Yisrael anochi karati berit et-avoteichem beyom hotzi oti otam me-eretz Mitzraim mibet avadim</strong>: &apos;Thus says the LORD, the God of Israel: I made a covenant with your ancestors when I brought them out of Egypt, out of the house of slavery.&apos; The appeal to the Exodus covenant grounds the slave-release law in the foundational liberation narrative. Israel&apos;s entire existence as a people begins with being freed from slavery by YHWH — this is why they cannot enslave each other indefinitely. <em>Beit avadim</em> (house of slavery) is the standard Exodus identification phrase (Exod 13:3, 14; 20:2; Deut 5:6). Those who were freed must not make their fellows the slaves YHWH freed them from being.</p>",
    "14": "<p><strong>miqetz sheva shanim teshalechu ish et-achiv ha-ivri asher yimacher lecha</strong>: &apos;At the end of seven years, every one of you must release a fellow Hebrew who has been sold to you.&apos; The Sabbatical-year law (Deut 15:12-18; Exod 21:2): six years of service, release in the seventh. The social logic: the number seven embeds the release in the Sabbath structure — just as the land rests every seventh year (Lev 25), so the enslaved person is released. The violation is not merely economic but cosmological: it disrupts the Sabbatical rhythm built into creation. The indictment &apos;your fathers did not listen to me or give me their attention&apos; (<em>velo shemu avoteichem elai velo hitu et-aznam</em>) establishes a centuries-long pattern of ignoring this law.</p>",
    "15": "<p><strong>vatashvu atem hayom vata&apos;asu et-hayashar be-einai liqro deror ish le-re&apos;ehu</strong>: &apos;And you — just recently you turned back and did what was right in my eyes, each of you proclaiming liberty to your neighbor.&apos; The acknowledgment of the momentary act of covenant obedience: &apos;you did what was right in my eyes&apos; (<em>ha-yashar be-einai</em>) — the highest covenant commendation (used of David in 1 Kgs 14:8; 15:5). The covenant was made in the house bearing YHWH&apos;s name (<em>la-shem alav</em>), the temple — the public, sacred context that maximizes the gravity of the subsequent breach.</p>",
    "16": "<p><strong>vatashuvah vatechalelu et-shemi vatashivu ish et-avdo ve&apos;ish et-amatoh</strong>: &apos;But then you turned back and profaned my name: each of you took back the male and female slaves you had set free.&apos; <em>Chalal shem YHWH</em> (profane/desecrate the name of the LORD) — the same term for violating what is holy (Lev 18:21; 19:12; 20:3; Ezek 36:20-23). Making a covenant oath before YHWH and then breaking it is not merely economic recidivism but blasphemy: it treats YHWH&apos;s name as surety for a promise and then repudiates both the promise and the surety.</p>",
    "17": "<p><strong>lachen koh-amar YHWH atem lo-shema&apos;tem elai liqro deror ish el-achiv ve-ish el-re&apos;ehu hineni qore lachem deror neum YHWH el-hacherev el-hadever ve&apos;el-hara&apos;av</strong>: &apos;Therefore thus says the LORD: You have not obeyed me by proclaiming liberty ... So now I am proclaiming liberty for you — liberty to the sword, to pestilence, and to famine.&apos; The bitter irony: the Hebrew word <em>deror</em> (liberty) used of the slave-release is now applied to the sword, famine, and pestilence — they are &apos;liberated&apos; to range freely among the people. The covenant logic of Lev 26:25 is enacted: the covenant curses &apos;avenge the covenant&apos; when it is broken. Refusing to proclaim <em>deror</em> to people results in YHWH proclaiming <em>deror</em> to the judgments against them.</p>",
    "18": "<p><strong>venatati et-ha-anashim haovrim et-beriti asher lo-qamu et-divrei haberit asher karu lifnai levein batrei ha-egel asher karu lishtayim</strong>: &apos;And I will hand over the men who violated my covenant ... when they cut the calf in two and passed between its parts.&apos; The covenant-cutting ceremony (<em>karat berit</em>, literally &apos;to cut a covenant&apos;) with its divided animal is the Gen 15 pattern: YHWH himself passes between the animal halves in the form of the smoking fire-pot and flaming torch, making himself the implied sacrifice if the covenant is violated. Here the humans passed between the parts — making themselves the implied sacrifice. YHWH is calling in the covenant sanction: those who passed between the calf-halves will become like the calf — cut in pieces, exposed as carrion (v. 20).</p>",
    "19": "<p>The comprehensive list of those who passed between the calf halves — officials of Judah, officials of Jerusalem, court officials, priests, and all the people — establishes that the covenant-oath violation is community-wide, not confined to a few individuals. The entire leadership structure of Judah participated in the broken oath, making the judgment comprehensive.</p>",
    "20": "<p><strong>venatati otam beyad oyveihem uveyad mevaqashei nafisham vehayetah nivlatam lema-achal le-of hashamayim ulivehmat ha-aretz</strong>: &apos;I will give them into the hands of their enemies ... Their dead bodies will become food for the birds of the sky and the beasts of the earth.&apos; The death without burial is the covenant curse of Deut 28:26: &apos;your carcasses will be food for all the birds of the air and the beasts of the earth.&apos; It also mirrors the fate the Babylonian armies threatened Jerusalem with, turned back on those who made covenant-oaths and broke them. The birds and beasts consume what was supposed to be buried — the final degradation of covenant violation.</p>",
    "21": "<p><strong>ve-et Tzidqiyahu melech Yehudah ve-et-sarav ettein beyad oyveihem</strong>: The king and his officials receive the same fate as the slave-owners — inclusion in the judgment is comprehensive across social strata. The army that &apos;pulled back from you&apos; (<em>ha-olim me-aleichem</em>) is the temporary Babylonian withdrawal to deal with the Egyptian relief force — the very event that prompted the slave-owners to rescind their liberation. The army&apos;s return is announced in v. 22.</p>",
    "22": "<p><strong>hineni metzaveh neum YHWH vahashivotim el-ha-ir hazot venilchamu aleiha</strong>: &apos;I am about to give the command, declares the LORD, and I will bring them back to this city. They will fight against it, take it, and burn it with fire.&apos; The divine command that turns the Babylonian army around: YHWH directs the movements of foreign armies as instruments of covenant judgment (cf. Isa 10:5-6: &apos;Woe to Assyria, the rod of my anger&apos;; Isa 45:1: Cyrus as YHWH&apos;s anointed). The certainty of the return is grounded not in military intelligence but in divine decree.</p>"
  },
  "35": {
    "1": "<p>The chapter is dated to Jehoiakim&apos;s reign — historically earlier than the surrounding chapters (605-597 BCE vs. 587 BCE for ch. 34). The retrospective placement serves a theological purpose: the Rechabites&apos; faithfulness is the immediate contrast to Jerusalem&apos;s unfaithfulness in ch. 34. Jeremiah is constructing a case by contrast.</p>",
    "2": "<p><strong>lek el-beit haRechabim vedibarta otam vahave&apos;otam beit YHWH</strong>: &apos;Go to the house of the Rechabites, speak with them, and bring them to the house of the LORD, into one of the inner rooms, and offer them wine to drink.&apos; The Rechabites were a nomadic clan descended from Jonadab son of Rechab (2 Kgs 10:15-23) who refused wine, houses, and agriculture as a covenant commitment to a nomadic, austere form of life. Jeremiah is instructed to test their obedience publicly by offering them the very thing their ancestor prohibited — in the temple itself, before witnesses.</p>",
    "3": "<p>The full genealogy of Jaazaniah — four generations named — establishes the lineage and historicity of the Rechabite household. The detail signals that this is a real family with a documented ancestral tradition, not a hypothetical case study.</p>",
    "4": "<p>The specific chamber (<em>lishkat benei Hanan ben-Igdalyahu ish ha-elohim</em>, the chamber of Hanan son of Igdaliah, the man of God) is noteworthy: a chamber associated with a prophetic figure (&apos;the man of God&apos;) was the location of the test. Adjacent to the officials&apos; chambers and above a priestly chamber — the setting is at the intersection of prophetic, official, and priestly spaces, maximizing the public and institutional nature of the test.</p>",
    "5": "<p><strong>va-eten lifnei benei beit haRechabim gevi&apos;im melaim yayin veqosot va-omar aleichem shetu yayin</strong>: &apos;Then I placed before the members of the Rechabite household pitchers full of wine and cups, and I said to them: Drink wine.&apos; The test is entirely formal: Jeremiah personally offers the wine in an authoritative setting. The Rechabites&apos; refusal therefore cannot be attributed to social awkwardness or lack of opportunity — it is a deliberate, articulate response to a direct invitation from a prophet in the temple.</p>",
    "6": "<p><strong>vayomru lo nishteh yayin ki Yonadav ben-Rechav avinu tzivanu lemor lo tishteu yayin atem uvneichem ad-olam</strong> (<em>wayyōmĕrû lōʾ nište yayin kî yônādāb ben-rēḵāb ʾābînû ṣiwwānû lēmōr lōʾ tišĕtû-yayin ʾattem ûbĕnekem ʿad-ʿôlām</em>): &apos;But they replied: We will not drink wine, for Jonadab son of Rechab, our father, commanded us: You shall not drink wine, you or your sons, ever.&apos; The response is immediate and communal — the entire household speaks with one voice. The reference to their ancestor&apos;s command (<em>tzivanu</em>) as authoritative is the key: they are not deciding in the moment but citing an inherited, binding obligation. <em>Ad-olam</em> (forever/in perpetuity) — the command had no sunset clause; it was meant to define Rechabite identity across generations.</p>",
    "7": "<p><strong>uvayit lo tivnu vezera lo tizre&apos;u vekharem lo titaa velo yihyeh lachem</strong>: &apos;You shall not build a house, sow seed, or plant a vineyard or own one. You shall live in tents all your days.&apos; The Rechabite lifestyle was a deliberate rejection of the settled agricultural economy that Israel had adopted in Canaan and that was associated with Baal worship (the fertility cult). By refusing houses, vineyards, and cultivation, the Rechabites embodied a counter-cultural testimony to the nomadic covenant-relationship with YHWH, deliberately maintained against the dominant culture. The motivation (<em>lema&apos;an tichyu yamim rabbim al-pnei ha-adamah asher atem garim sham</em>, so that you may live long in the land where you are strangers) makes longevity in the land contingent on faithfulness — the same structure as the covenant&apos;s land-tenure conditions.</p>",
    "8": "<p>The collective voice of the Rechabites: <em>vanishma beqol Yonadav ben-Rechav avinu lechol asher tzivanu</em> (we have obeyed the voice of Jonadab son of Rechab, our father, in everything he commanded us). The contrast with Israel&apos;s &apos;we did not listen&apos; (<em>lo shama&apos;nu</em>, v. 14-17) is the entire point: a human ancestor commanded, and his descendants obeyed for generations; YHWH the Creator commanded, and his covenant people persistently disobeyed.</p>",
    "9": "<p>The specific enumeration of what they have NOT done — not built houses, not owned vineyards or fields or seeds — follows the ancestral commands of v. 7 point by point. The listing is deliberate: each negative corresponds to a cultural norm they have refused. The Rechabite testimony is structured as a covenant affirmation: here is the command, and here is what we have done and not done in response.</p>",
    "10": "<p><strong>vaneshev ba-ohalim venishma vanase&apos;ah lechol asher tzivanu Yonadab avinu</strong>: &apos;We have lived in tents and have obeyed and done all that our father Jonadab commanded us.&apos; The summary claim: full and comprehensive obedience. The tents are the physical sign of their covenant identity — portable, impermanent, dependent on YHWH rather than on landed security. The wilderness ideal maintained into the era of urban civilization.</p>",
    "11": "<p><strong>vayhi bia&apos;lot Nevukhadreatzar melech Bavel al-ha-aretz vanomer bo vanavo Yerushalaim</strong>: &apos;But when Nebuchadrezzar king of Babylon came up against the land, we said: Come, let us go to Jerusalem for fear of the Chaldean army and the Syrian army. That is why we are living in Jerusalem now.&apos; The exception proves the rule: even the Rechabites, bound by their ancestor&apos;s nomadic ideal, had to take refuge in a city under existential military threat. The concession is practical and explicitly temporary — they are &apos;living in Jerusalem now,&apos; not permanently settling. The crisis has forced a tactical retreat from their lifestyle, but not from their values.</p>",
    "12": "<p>The messenger formula introducing the theological application. YHWH now draws the lesson from the Rechabite test — the observation of their obedience becomes the indictment of Israel&apos;s disobedience.</p>",
    "13": "<p><strong>koh amar YHWH Tzvaot elohe Yisrael lech ve-amarta el-anshei Yehudah ve-el yoshevei Yerushalaim halo tiqchu musar lishmo&apos;a el-devarai neum YHWH</strong>: &apos;Go and say to the people of Judah and the inhabitants of Jerusalem: Will you not receive instruction and listen to my words?&apos; <em>Musar</em> (instruction/discipline/correction) is the wisdom term for the teachable reception of correction. The Rechabites received and implemented their father&apos;s <em>musar</em>; Jerusalem refuses YHWH&apos;s. The rhetorical question (<em>halo tiqchu musar</em>) expects the answer &apos;yes, you should&apos; but acknowledges by implication the answer has been &apos;no.&apos;</p>",
    "14": "<p><strong>huqam mitzvat Yonadav ben-Rechav asher tzivah et-banav levilti shtot yayin ve&apos;azoh lo shatu ad-hayom hazeh ki shamu et-mitzvat avihem</strong>: &apos;The command that Jonadab son of Rechab gave to his sons — to drink no wine — has been kept. To this day they drink none, because they have obeyed their ancestor&apos;s command. But I have spoken to you persistently, and you have not listened to me.&apos; The pivotal contrast: Jonadab commanded; they obeyed. YHWH spoke persistently (<em>hashkem vediber</em>, rising early and speaking — the idiom for urgent, repeated communication); they did not listen. The theological force: a human ancestor commands more effectively than the divine Creator. The question implicit in the contrast: why? The answer Jeremiah&apos;s book returns to repeatedly: the stubborn, rebellious heart (<em>lev sorer u-moreh</em>, 5:23).</p>",
    "15": "<p><strong>va-eshlach aleichem et-kol-avadai haneviim hashkem ve-shloch lemor shuvu na ish midarcho hara-ah</strong>: &apos;I have sent you all my servants the prophets, again and again, saying: Turn now, each of you, from your evil way.&apos; The phrase <em>hashkem veshalloach</em> (rising early and sending) — the urgency-idiom for repeated, insistent communication (cf. 7:13, 25; 11:7; 25:3-4; 26:5; 29:19; 32:33; 44:4). YHWH has been &apos;early and persistent&apos; in sending prophets; Israel has been persistent in not listening. The contrast between YHWH&apos;s urgency and Israel&apos;s indifference is one of Jeremiah&apos;s central theological themes.</p>",
    "16": "<p><strong>vayaqimu benei Yonadav ben-Rechav et-mitzvat avihem asher tzivam veha-am hazeh lo shamu elai</strong>: &apos;The descendants of Jonadab son of Rechab have kept their father&apos;s command, but this people has not obeyed me.&apos; The direct comparison. The indictment is stark in its brevity: eight words in Hebrew. The Rechabites&apos; multi-generational obedience to a human ancestor versus Israel&apos;s persistent disobedience to the divine Father who gave them the covenant from Sinai.</p>",
    "17": "<p><strong>lachen koh-amar YHWH Tzvaot elohe Yisrael hineni mevi el-Yehudah ve-el-kol yoshevei Yerushalaim et kol-hara-ah asher dibarti aleichem</strong>: &apos;Therefore thus says the LORD, the God of hosts, the God of Israel: I am going to bring on Judah and all the inhabitants of Jerusalem all the disaster I have pronounced against them.&apos; The logical consequence is stated without elaboration — the argument of vv. 13-16 has made it self-evident. The comprehensive titles (<em>YHWH Tzvaot elohe Yisrael</em>) frame the judgment as both universal sovereign and covenant-specific God: the disaster comes not from an impersonal force but from the God who is personally invested in the covenant.</p>",
    "18": "<p><strong>uveit haRechabim amar Yirmiyahu koh-amar YHWH Tzvaot elohe Yisrael ya-an asher shema&apos;tem et-mitzvat Yonadav avichem</strong>: &apos;Because you have obeyed the command of Jonadab your father and kept all his instructions and done all that he commanded you.&apos; The threefold statement of obedience — <em>shematem</em> (listened to), <em;>tishmerou</em> (kept), <em>ta-asu</em> (did) — hearing, retention, and action: the complete circuit of covenantal obedience. Each element represents a dimension of faithfulness: hearing the command, retaining it across generations, and enacting it in practice.</p>",
    "19": "<p><strong>lachen koh-amar YHWH Tzvaot elohe Yisrael lo-yikaret ish liYonadav ben-Rechav omed lefanai kol-hayamim</strong> (<em>lākēn kōh-ʾāmar Yhwh ṣĕbāʾôt ʾĕlōhê yiśrāʾēl lōʾ-yikkārēt ʾîš lĕyônādāb ben-rēḵāb ʿōmēd lĕpānay kol-hayyāmîm</em>): &apos;Therefore thus says the LORD of hosts, the God of Israel: Jonadab son of Rechab shall never fail to have a man standing before me.&apos; <em>Omed lefanai</em> (standing before me) is the covenant phrase for priestly and prophetic service (Deut 10:8; 1 Kgs 17:1; Jer 15:19). The Rechabites are promised perpetual covenantal standing — the same guarantee given to the Davidic line (33:17) and the Levitical priesthood (33:18). Faithfulness to covenant obligations is rewarded with covenantal continuity.</p>"
  },
  "36": {
    "1": "<p>The fourth year of Jehoiakim (605 BCE) is the year of the battle of Carchemish, when Nebuchadnezzar defeated Egypt and became the dominant power in the ancient Near East — the decisive geopolitical turning point that validates Jeremiah&apos;s northern-foe oracles. The command to write comes at this moment of historical confirmation.</p>",
    "2": "<p><strong>qach lecha megillat sefer vechatavta eleiha et kol-hadvarim asher dibarti eleicha al-Yisrael ve-al-Yehudah ve-al-kol-hagoyim miyom dibbarti eleicha miyemei Yoshiyahu ve-ad hayom hazeh</strong>: &apos;Take a scroll and write in it all the words I have spoken to you against Israel, against Judah, and against all the nations, from the day I first spoke to you in the days of Josiah until this day.&apos; <em>Megillat sefer</em> (scroll of a book) — the Hebrew writing medium of the period. The command to write is unprecedented in Jeremiah&apos;s ministry up to this point: twenty-plus years of prophetic activity are now to be committed to permanent record. The scroll will outlast its oral delivery and reach those who were not present to hear. This chapter is self-referentially about the nature and indestructibility of the written word.</p>",
    "3": "<p><strong>ulai yishme&apos;u beit Yehudah et kol-hara-ah asher anochi choshev la-asot lahem lema-an yashuvu ish midarcho hara-ah</strong>: &apos;Perhaps the house of Judah will hear of all the disaster I intend to bring on them, so that each person will turn from his evil way, and I will forgive their iniquity and their sin.&apos; The divine motive for writing: restoration through repentance remains the goal. Even at this late stage — the battle of Carchemish has confirmed the worst — YHWH leaves open the possibility of repentance and forgiveness. <em>Ulai</em> (perhaps) is not divine uncertainty but prophetic openness: the door is not closed until it is demonstrably closed.</p>",
    "4": "<p><strong>vayiqra Yirmiyahu et-Baruch ben-Neriyah vayichtov Baruch mipi Yirmiyahu et kol-divrei YHWH asher diber elav al-megillat sefer</strong>: &apos;So Jeremiah summoned Baruch son of Neriah, and Baruch wrote on a scroll everything Jeremiah dictated to him — all the words of the LORD that had been spoken to Jeremiah.&apos; Baruch son of Neriah is Jeremiah&apos;s scribe and the likely primary editor of the book of Jeremiah. A seal (<em>bulla</em>) bearing the inscription &apos;Belonging to Berekhyahu son of Neriyahu the scribe&apos; was found among the Moussaieff collection, dated to the sixth century BCE — an extraordinary extra-biblical confirmation of Baruch&apos;s historical existence and professional title.</p>",
    "5": "<p><strong>vaytzav Yirmiyahu et-Baruch lemor ani atzur lo uchal lavo beit YHWH</strong>: &apos;Jeremiah gave Baruch these instructions: I am banned; I cannot go to the house of the LORD.&apos; <em>Atzur</em> (banned/confined/prevented) — the cause of Jeremiah&apos;s ban is not specified here, but may be related to his temple sermon (ch. 7, 26) or earlier controversies. His inability to deliver the scroll personally necessitates Baruch&apos;s role as his agent — a role Baruch takes on with apparent courage, since reading the scroll publicly would carry risk.</p>",
    "6": "<p><strong>uvata viqrata bamegillah asher katavta mipi et-divrei YHWH be-oznei ha-am beit YHWH beyom tzom</strong>: &apos;So you go and read from the scroll ... to all the people in the LORD&apos;s house on a day of fasting.&apos; The fast-day setting maximizes the audience: pilgrims from throughout Judah (<em>kol-anshei Yehudah haba-im me-areihem</em>) would be present for a communal fast. The public reading on a solemn occasion — when people are most psychologically prepared to hear weighty words — is the optimal context for the scroll&apos;s reception.</p>",
    "7": "<p><strong>ulai tipol techintam lifnei YHWH veyashuvu ish midarcho hara-ah</strong>: The same <em>ulai</em> (perhaps) of hope from v. 3 — the possibility of repentance remains. The petition (<em>techinnatam</em>) Jeremiah hopes the people will bring before YHWH echoes the temple dedication prayer structure (1 Kgs 8:46-53). The two-fold motivation — the &apos;great anger and wrath&apos; pronounced and the open door of forgiveness — frame the reading as both warning and invitation.</p>",
    "8": "<p>Baruch&apos;s obedience to Jeremiah&apos;s command: <em>vayya&apos;as Baruch ben-Neriyahu kekol asher tzivahu Yirmiyahu hanavi</em> (Baruch son of Neriah did exactly what the prophet Jeremiah commanded him). The precision mirrors the Rechabites&apos; obedience to their ancestor — but the command comes from a prophet, not merely a human ancestor.</p>",
    "9": "<p>The fifth year of Jehoiakim, ninth month (approximately December 604 BCE) — a specific calendar date. A communal fast was proclaimed, possibly in response to news of the Babylonian threat after Carchemish. The fast is an act of communal penitence or petition before YHWH — precisely the context for the scroll&apos;s message to be heard. The crowds from the towns of Judah (<em>kol-ha-am mi-arei Yehudah</em>) expand the reach beyond Jerusalem&apos;s population.</p>",
    "10": "<p><strong>vayiqra Baruch bamegilah et-divrei Yirmiyahu beit YHWH belishkat Gemariyahu ben-Shaphan hasopher bechatzer ha-elyon</strong>: &apos;Then Baruch read the words of Jeremiah from the scroll in the house of the LORD, in the chamber of Gemariah son of Shaphan the secretary.&apos; Gemariah son of Shaphan connects to the powerful Shaphan family that supported Jeremiah throughout his ministry (2 Kgs 22:3-14: Shaphan the secretary read the law-scroll to Josiah; Ahikam son of Shaphan protected Jeremiah in ch. 26). The chamber&apos;s location at the upper court, at the New Gate, gave maximum public access — the scroll was read in a major civic and religious space.</p>",
    "11": "<p>Micaiah son of Gemariah — Shaphan&apos;s grandson — hears the scroll and immediately takes the content to the court officials. The chain of transmission (scroll → Baruch → upper court → Micaiah → officials&apos; chamber) traces the word&apos;s movement from prophetic origin to political center. Each link is named, establishing accountability and historical memory.</p>",
    "12": "<p>The officials listed — Elishama the secretary, Delaiah son of Shemaiah, Elnathan son of Achbor (who had helped retrieve the prophet Uriah from Egypt, 26:22), Gemariah son of Shaphan, Zedekiah son of Hananiah — represent the upper tier of Jehoiakim&apos;s court. Their response (v. 16: they were afraid) differs markedly from the king&apos;s (v. 23-24: he showed no fear).</p>",
    "13": "<p>The reporting of Micaiah to the officials: the scroll&apos;s content is relayed through successive audiences — each hearing generating a response that shapes the next audience&apos;s encounter with the word. The word&apos;s movement through institutions is itself part of its narrative: it finds its way despite the obstacles.</p>",
    "14": "<p>The officials send for Baruch directly: <em>qach et-hamegillah asher qarata bah be-oznei ha-am ule-ch</em> (take the scroll from which you read to the people and come). Their summons uses the scroll as its subject — the scroll has its own identity as the locus of the word. Baruch comes with the scroll to the officials&apos; chamber.</p>",
    "15": "<p>The officials&apos; first response — &apos;Sit down and read it to us&apos; (<em>shev na veqra-ennu be-ozeinu</em>) — is one of respectful attention. They are alarmed but not hostile (v. 16). The contrast with Jehoiakim&apos;s response (vv. 23-24) is the pivot of the chapter: the officials respond with fear; the king responds with contempt.</p>",
    "16": "<p><strong>vayehi kishomam et kol-hadvarim pahedu ish el-re-ehu vayomru el-Baruch haged nagid lamelech et kol-hadvarim ha-elleh</strong>: &apos;When they heard all the words, they turned to one another in alarm and said to Baruch: We must report all these words to the king.&apos; <em>Pachadu</em> (alarm/fear) — the appropriate prophetic response to the divine word (cf. Isa 66:2, 5: &apos;this is the one I esteem: he who is humble and contrite in spirit, and trembles at my word&apos;). The officials hear the word and are afraid — the fear is right; the failure is that they report to the king rather than leading repentance from their position.</p>",
    "17": "<p>The officials&apos; investigative question — how did Baruch write all these words? (at Jeremiah&apos;s dictation?) — establishes the chain of authority for legal purposes: is this Baruch&apos;s composition or Jeremiah&apos;s, and is it the prophet&apos;s own word or YHWH&apos;s? The question also protects Baruch legally: it creates a record that he was acting as a scribe, not as a prophet making his own pronouncements.</p>",
    "18": "<p><strong>vayomer lahem Baruch mipi yiqra elai et kol-hadvarim ha-elleh va-ani kotev al-hasefer bedyo</strong>: &apos;Baruch answered them: He dictated all these words to me, and I wrote them in ink on the scroll.&apos; <em>Bedyo</em> (in ink) — a technical scribal note. The specificity of &apos;ink on a scroll&apos; underscores the permanence of the written word compared to the spoken oracle: this is now fixed in a physical medium that can be preserved, copied, and transmitted beyond the immediate audience.</p>",
    "19": "<p><strong>vayomru hasarim el-Baruch lek histater atah viYirmiyahu ve-ish al-yeda ei-zeh atem</strong>: &apos;Then the officials said to Baruch: Go and hide — you and Jeremiah — and let no one know where you are.&apos; The officials are protecting Jeremiah and Baruch from the king&apos;s anticipated rage. Their warning implies knowledge of Jehoiakim&apos;s character — they know what he will do when he hears the scroll. The intervention parallels earlier protection: Ahikam son of Shaphan protected Jeremiah in 26:24.</p>",
    "20": "<p>The scroll is stored in Elishama the secretary&apos;s chamber while the officials brief the king. The act of storage is significant: even before the king hears its contents, the scroll is being treated as a document requiring custody — both for preservation and as evidence. The officials apparently try to maintain the scroll&apos;s existence even while reporting its contents.</p>",
    "21": "<p><strong>vayishlach hamelech et-Yehudi laqachat et-hamegillah</strong>: &apos;The king sent Jehudi to get the scroll.&apos; The king sends a servant to retrieve the physical object — Jehoiakim wants the scroll itself, not just a report of its contents. The retrieval of the scroll from Elishama&apos;s chamber establishes that what follows is a deliberate, calculated act against the word itself, not an impulsive moment.</p>",
    "22": "<p><strong>vehamelech yoshev beit hachore bachodesh hateshii ve-et haach burneth lefanav</strong>: &apos;The king was sitting in the winter apartment in the ninth month, and there was a fire burning before him in the fire pot.&apos; The domestic detail — the king in his winter quarters, warming himself by the fire — creates the ironic tableau: the fire that warms the king will consume the word. The same fire that Jehoiakim uses for comfort will become the instrument of his act of defiance.</p>",
    "23": "<p><strong>vayehi ki qara Yehudi shalosh daltot ve-arba-ah yiqra-ennu vayikra-enhu hamelech bitar lapid hasopher vehishlikh el-ha-esh asher el-haach ad tom kol-hamegillah al-ha-esh</strong> (<em>wayhî kî-qārāʾ yĕhûdî šāloš dĕlātôt wĕʾarbaʿāh yiqrāʾennû wĕyiqrāʿehu hammelek bĕtaʿar hassōpēr wĕhišlîk ʾel-hāʾēš ʾăšer ʾel-hāʾaḥ ʿad tōm kol-hamĕgillāh ʿal-hāʾēš</em>): &apos;Each time Jehudi had read three or four columns, the king would cut the section off with a scribe&apos;s knife and throw it into the fire, until the entire scroll had been consumed.&apos; <em>Taar hasopher</em> (scribe&apos;s knife, penknife) — the tool used for cutting reed pens and trimming scrolls, now used for defacement. The deliberate, methodical destruction — column by column, not in a single outburst — makes the act calculated rather than impulsive: Jehoiakim is consciously and continuously destroying the word of God. The contrast with Josiah&apos;s response when he heard the law read (<em>qara et-bigadav</em>, he tore his garments — 2 Kgs 22:11) is complete: one king tears himself; the other tears the scroll.</p>",
    "24": "<p><strong>velo pakhadu velo qar-u et-bigdeihem hamelech vekhol-avadav hashom-im et kol-hadvarim ha-elleh</strong>: &apos;Yet neither the king nor any of his servants who heard all these words was afraid, nor did they tear their garments.&apos; <em>Lo pachadu velo qaru et-bigdeihem</em> (neither afraid nor did they tear their garments) — the double absence of appropriate response. Fear and garment-tearing were the two marks of authentic covenant response to YHWH&apos;s word (2 Kgs 22:11, 19: Josiah tore his garments; Hezekiah sent messengers with torn garments to Isaiah in Isa 37:1). The king and his servants have hardened hearts that cannot receive the word — the Pharaoh-analogy is implicit: Exod 7:13, 22 (&apos;Pharaoh&apos;s heart was hardened&apos;) uses the same vocabulary of stubborn non-response.</p>",
    "25": "<p><strong>vegam Elnathan veDel-ayahu veGamarayahu pichalelu ba-melech levilti srifal et-hamegillah velo shama aleichem</strong>: &apos;Even though Elnathan and Delaiah and Gemariah pleaded with the king not to burn the scroll, he would not listen to them.&apos; Three officials (including Gemariah son of Shaphan, who had provided the chamber for the public reading) interceded on behalf of the scroll. Their pleading (<em>hiphgilu</em>) is the same word used for prophetic intercession — they are using prophetic-style advocacy for the preservation of the prophetic word. The king&apos;s refusal to listen to them mirrors his refusal to listen to the scroll.</p>",
    "26": "<p><strong>vaytzav hamelech et-Yerachmeel ben-hamelech ve-et-Seraya ben-Azriel ve-et-Shelemyahu ben-Avdeel laqachat et-Baruch hasopher ve-et-Yirmiyahu hanavi vayastirem YHWH</strong>: &apos;The king commanded Jerahmeel a royal prince, Seraiah son of Azriel, and Shelemiah son of Abdeel to seize Baruch the scribe and Jeremiah the prophet. But the LORD hid them.&apos; <em>Vayastirem YHWH</em> (but the LORD hid them) — the divine protection intervenes at the moment of royal persecution. The brevity of the clause — four Hebrew words — is its strength: no explanation of how, simply the fact that YHWH protected what Jehoiakim sought to destroy. The same word <em>sitr</em> (hide) appears in 33:3&apos;s &apos;hidden things&apos; (<em>betzurot</em>) — but now it is not revelation that is hidden but the prophet himself, preserved by divine concealment.</p>",
    "27": "<p>After the scroll&apos;s destruction, the word of YHWH comes to Jeremiah — the divine response to the burning. The indestructibility of the word is the oracle&apos;s premise: burning the scroll does not destroy the word; it only generates a second, fuller scroll.</p>",
    "28": "<p><strong>shuv qach lecha megillah acheret vechtovchetah aleha et kol-hadvarim harishonim asher hayu al-hamegillah harishonah asher saraf Yehoyaqim melech Yehudah ba-esh</strong>: &apos;Take another scroll and write on it all the same words that were in the first scroll, the one Jehoiakim king of Judah burned.&apos; The command to replace the destroyed scroll is the theological statement: the word of YHWH cannot be annihilated by human action. This is the OT enactment of what Jesus will claim: &apos;heaven and earth will pass away, but my words will never pass away&apos; (Matt 24:35; Mark 13:31; Luke 21:33). The word outlasts the political power that seeks to silence it.</p>",
    "29": "<p><strong>ve-al Yehoyaqim melech Yehudah tomar koh-amar YHWH atah sarafta et-hamegillah hazot lemor madu katavtah aleiha lemor bo yavo melech Bavel veshichet et-ha-aretz hazot</strong>: &apos;And concerning Jehoiakim king of Judah you shall say: Thus says the LORD — You burned this scroll, asking: Why have you written in it that the king of Babylon will certainly come and destroy this land?&apos; The oracle is addressed directly to Jehoiakim&apos;s act of burning — YHWH names the specific question behind the destruction: Jehoiakim burned the scroll because he rejected the Babylonian-threat oracle it contained. The burning is an act of wishful thinking — destroy the word and the future it announces will not come. The divine response makes the burning ineffective and the burning-king the new subject of prophecy.</p>",
    "30": "<p><strong>lachen koh-amar YHWH al-Yehoyaqim melech Yehudah lo-yihyeh lo yoshev al-kise David venivlatoh tihyeh mushleket lechoreh yomam velaqarachah laylah</strong>: &apos;Therefore thus says the LORD concerning Jehoiakim king of Judah: He will have no one to sit on the throne of David, and his dead body will be cast out to the heat of the day and the frost of the night.&apos; The throne-denial echoes the Coniah curse of 22:30 (&apos;none of his descendants will succeed in sitting on the throne of David&apos;) — consistent: Jehoiakim&apos;s son Jehoiachin reigned only three months before being deported; neither he nor any descendant ever ruled Judah as an independent king. The exposed body (<em>mushleket</em>) mirrors the &apos;buried like a donkey&apos; oracle of 22:19.</p>",
    "31": "<p><strong>ufaqadeti alav ve-al-zaro ve-al-avadav et-avonam</strong>: &apos;I will punish him and his offspring and his servants for their iniquity.&apos; The <em>paqad avon</em> (punish iniquity / visit iniquity) formula — the covenant curse-enactment. The household solidarity of punishment (king + offspring + servants) is the corporate consequence of covenantal violation. The repeated phrase &apos;because they would not listen&apos; (<em>ya-an asher lo shamu</em>) makes refusal to hear the single sufficient explanation for everything that follows.</p>",
    "32": "<p><strong>viYirmiyahu laqach megillah acheret vayitenah el-Baruch ben-Neriyahu hasopher vayichtov aleiha mipi Yirmiyahu et kol-divrei hasefer asher saraf Yehoyaqim melech Yehudah ba-esh vaiyosef aleichem od devarim rabbim kehamah</strong>: &apos;Then Jeremiah took another scroll and gave it to Baruch son of Neriah the scribe, who wrote on it at Jeremiah&apos;s dictation all the words of the scroll that Jehoiakim king of Judah had burned. And many similar words were added to them.&apos; The burned scroll is replaced — and exceeded. <em>Vayosef aleichem od devarim rabbim kehamah</em> (many similar words were added to them): the attempt to silence the word results in more words than before. The pattern of attempted suppression leading to amplification of the word is the dynamic of the entire canon: persecution does not diminish the word but occasions its expansion. The book of Jeremiah itself — 52 chapters — is the final ironic monument to Jehoiakim&apos;s burning of the first scroll.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'jeremiah')
    merge_comm(existing, JER_ORIGINAL)
    save_comm('mkt-original', 'jeremiah', existing)

    out = json.loads((ROOT / 'data/commentary/mkt-original/jeremiah.json').read_text())
    il  = json.loads((ROOT / 'data/interlinear/jeremiah.json').read_text())

    all_ok = True
    for ch in range(33, 37):
        ck = str(ch)
        missing = set(il.get(ck, {}).keys()) - set(out.get(ck, {}).keys())
        if missing:
            print(f'ch {ch} STILL MISSING: {sorted(missing, key=int)}')
            all_ok = False
        else:
            print(f'ch {ch}: complete ({len(out.get(ck,{}))} verses)')
    if all_ok:
        print('All verses present')

if __name__ == '__main__':
    main()
